                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , pAllSearch
                , "작업장,작업장코드,작업장명"
            );
            break;
        case 'CS':
            // 샤샤
            udc_wrkPlCdG.setSelectId("retrieveChassis2")
            udc_wrkPlCdG.cfCommonPopUp(scwin.udc_CS_callBackFunc
                , pCode
                , pName
                , pClose
                , null
