        , odrNo + "," + wrkPlCd + "," + crryinoutIntendNo + "," + cntrSizCd + "," + cntrTypCd		// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
        , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
        , null					// 윈도우 위치 Y좌표	
        , null					// 윈도우 위치 X좌표
        , null					// 중복체크여부	("F")
        , "T"					// 전체검색허용여부("F")
        , null					// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        , null
        , null
    );
};

