        //gr_gridView.ColumnProp("gridChkBox", "Edit", "true");

        if (ds_outGrid.getCellData(scwin.pre_RowPosition, 'cntrNoYn') == "1") {    //컨테이너번호 수정인 경우
            if (rowCnt == 0 || ds_outCntrNoChangeInfo.getCellData(0, 'odrCntrNoYn') == "0") {    //컨테이너정보(TB_SD404) 또는 오더 컨테이너(TB_SD403)에 컨테이너 번호 미등록된 경우
