scwin.f_crryInOutEDI = function (bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag, transWrkIndictNo) {
    if (ds_outGrid.getRowCount() == 0) {
        return;
    }

    if (ds_outGrid.getCellData(row, "chkFlag") != "C" && scwin.copinoManualSndYn == 0) {
        $c.gus.cfAlertMsg("미처리된 항목입니다. 처리된 항목만 전송 할 수 있습니다.");
        return;
    }

    if (ds_outGrid.getCellData(row, "crryoutEdiType") == "N" && ds_outGrid.getCellData(row, "crryinEdiType") == "N") {
        $c.gus.cfAlertMsg("EDI전송 대상이 아닙니다");
        return;
    }
    if (ds_outGrid.getCellData(row, "vehclNo") == "") {
        if (bAlertFlag) {
            $c.gus.cfAlertMsg("운송차량이 없습니다");
        }
        return false;
    }

    //    var rtnList = new Array();
    //    var arrParam = new Array();
    var dptWrkPlCd = "";
    var arvWrkPlCd = "";
    var dptWrkPlNm = "";
    var arvWrkPlNm = "";

    if (ds_outGrid.getCellData(row, 'crryinoutClsCd') == "I") {
        dptWrkPlCd = ds_outGrid.getCellData(row, "dptArvWrkPlCd");
        arvWrkPlCd = ds_outGrid.getCellData(row, "wrkPlCd");
        dptWrkPlNm = ds_outGrid.getCellData(row, "wrkPlNm");
        arvWrkPlNm = txt_wrkPlNm.getValue();
    } else if (ds_outGrid.getCellData(row, 'crryinoutClsCd') == "O") {
        dptWrkPlCd = ds_outGrid.getCellData(row, "wrkPlCd");
        arvWrkPlCd = ds_outGrid.getCellData(row, "dptArvWrkPlCd");
        dptWrkPlNm = txt_wrkPlNm.getValue();
        arvWrkPlNm = ds_outGrid.getCellData(row, "wrkPlNm");
    }

    if (transWrkIndictNo == "") {
        transWrkIndictNo = ds_outGrid.getCellData(row, "transWrkIndictNo");
    }

    if (transWrkIndictNo == "" || transWrkIndictNo == null) {
        transWrkIndictNo = ds_transWrkIndictNo.getCellData(0, 'value');
    }

    var arrParam = new Array();

    let data = {
        paramTitle: "반출입정보EDI등록",
        crryoutEdiType: ds_outGrid.getCellData(row, "crryoutEdiType")
        , crryinEdiType: ds_outGrid.getCellData(row, "crryinEdiType")
    };
    arrParam[0] = new Array(
        "1"  // 조회구분 ("" : 운송작업지시, "1" : 반출입)
        , transWrkIndictNo
        , ds_outGrid.getCellData(row, "odrNo")
        , ds_outGrid.getCellData(row, "cntrSeq")
        , ds_outGrid.getCellData(row, "wrkPathSeq")
        , ds_outGrid.getCellData(row, "wrkStpSeq")
        , ds_outGrid.getCellData(row, "vehclShortNo")
        , ds_outGrid.getCellData(row, "vehclNo")
        , ds_outGrid.getCellData(row, "vehclIdCardNo")
        , ds_outGrid.getCellData(row, "wrkStDt")
        , ds_outGrid.getCellData(row, "wrkEndDt")
        , ds_outGrid.getCellData(row, "cntrNo")
        , dptWrkPlCd
        , arvWrkPlCd
        , dptWrkPlNm
        , arvWrkPlNm
        , ds_outGrid.getCellData(row, "crryoutEdiType")
        , ds_outGrid.getCellData(row, "crryinEdiType")
    );
    arrParam[1] = new Array(
        transWrkIndictNo
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "vehclNo")
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "vehclIdCardNo")
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "drvNm")
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "drvTelNo")
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "gateoutDth").substring(0, 8)
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "gateoutDth").substring(8, 12)
        , ""
        , ""
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "vehclShortNo")
        , ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "eqCd")
    );
    //        , callbackFn: scwin.f_crryInOutEDI_callBackFunc
    //    };
    data.arrParam = arrParam;
    var opts = {
        id: "smpPop"
        , popupName: "반출입정보EDI등록"
        , modal: true
        , type: "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title: "Win pop"  //Layer pop
        , width: 1000
        , height: 930
    };

    $c.win.openPopup("/ui/ds/op/wrkplan/transwrkplan/op_202_02_23p.xml", opts, data).then(
        function (rtnList) {
            scwin.f_crryInOutEDI_callBackFunc(rtnList);
        });
};

