};

//-------------------------------------------------------------------------
// function name : f_GateoutProcess
// function desc : GateOut 처리
//-------------------------------------------------------------------------
scwin.btn_gateoutProcessAS_onclick = function (e) {
    scwin.f_gateoutProcess('Auto');
};

scwin.btn_gateoutProcessMS_onclick = function (e) {
    scwin.f_gateoutProcess('Manual');
};

scwin.btn_gateoutProcess_onclick = function (e) {
    scwin.f_gateoutProcess('');
};

scwin.f_gateoutProcess = async function (p_gubun) {
    //경인ICD의 경우 Copino자동전송 되도록 .
    /*
    if( ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "dptArvWrkPlCd") == "4C02"
      || ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "dptArvWrkPlCd") == "4R01" ) {
        p_gubun = "Auto";
    }
    */

    var gridChkYn = 0;
    var copinoAutoSndYn = 0;
    scwin.copinoManualSndYn = 0;

    for (var i = 0; i < ds_outGrid.getRowCount(); i++) {
        if (ds_outGrid.getCellData(i, 'gridChkBox') == 1) gridChkYn++;

        //ANL,APL 부킹체크 
        //황창기 20161208 APL 라인추가
        if (ds_outGrid.getCellData(i, 'gridChkBox') == "1"
            && (ds_outGrid.getCellData(i, "lineCd") == "ANL" || ds_outGrid.getCellData(i, "lineCd") == "APL")
            && ds_outGrid.getCellData(i, "fullEmptyClsCd") == "E"
            && ed_wrkPlCd.getValue() == "4C02") {
            await scwin.f_retrieveANLBookingDetail(i);

            if (ds_resultsANLBooking.getCellData(0, "pickupdt") == '') {
                if (ds_outGrid.getCellData(i, "lineCd") == "APL") {
                    $c.win.alert("반출불가\nBOOKING 수신 내역이 없습니다.");
                }
                else {
                    $c.win.alert("반출불가\nBOOKING 수신 내역이 없습니다.[ANL반출제어]");
                    return;
                }
            } else {
                // ANL,APL 라인일경우 픽업일자포함 +3일까지 반출가능 2017.10.17 서동원 추가 
                var betDt = $c.date.diffDate(ds_resultsANLBooking.getCellData(0, 'pickupdt'), ds_outGrid.getCellData(i, "gateoutDth").substr(0, 8));
                //Math.floor((ds_resultsANLBooking.get('pickupdt') - ds_outGrid.getCellData(i, "gateoutDth").substr(0, 8)) / 1000 / 60 / 60 / 24); 
                //cfDaysBetween(ds_resultsANLBooking.get('pickupdt'), ds_outGrid.getCellData(i, "gateoutDth").substr(0, 8));
                //$c.date.diffDate(ds_resultsANLBooking.get('pickupdt'), ds_outGrid.getCellData(i, "gateoutDth").substr(0, 8));
                if (!(betDt == "0" || betDt == "1" || betDt == "2")) {
                    $c.gus.cfAlertMsg('해당 BK의 픽업일자는 ' +
                        ds_resultsANLBooking.getCellData(0, 'pickupdt').substr(0, 4) + '/' +
                        ds_resultsANLBooking.getCellData(0, 'pickupdt').substr(4, 2) + '/' +
                        ds_resultsANLBooking.getCellData(0, 'pickupdt').substr(6, 2) + '  ' +
                        '입니다. \n 반출일시를 확인하시기 바랍니다. 반출일시는 픽업일자 포함 +3일까지 반출이 가능합니다.');
                    return;
                }
            }
        }
        var iRow = i + 1;
        if (ds_outGrid.getCellData(i, 'gridChkBox') == "1" && ds_outGrid.getCellData(i, 'gateoutDth').length != 12) {
            $c.win.alert(iRow + "번째 데이터에서 반출일시를 확인 하십시요.");
            return;
        }
        if (ds_outGrid.getCellData(i, 'gridChkBox') == "1" && ds_outGrid.getCellData(i, 'chkFlag') == "C") {
            $c.win.alert(iRow + "번째 항목은 이미 반출완료된 항목 입니다.");
            return;
        }
        //COPINO 자동전송
        /*if( p_gubun == "Auto"
            && (ds_outGrid.getCellData(i,'preInfoSndYn') == "1" || ds_outGrid.getCellData(i,'dptArvPreInfoSndYn') == "1")
            && ds_outGrid.getCellData(i,'selfClsCd') != "<%//=DsConstants.SELF_CLS_CD_SELF_CRRYOUT
            && ds_outGrid.getCellData(i,'gridChkBox') == 1 ) {
            ds_outGrid.setCellData(i,'copinoAutoSndYn', "1");
            copinoAutoSndYn = 1;
        }*/

        if (p_gubun == "Auto"
            && (ds_outGrid.getCellData(i, 'preInfoSndYn') == "1" || ds_outGrid.getCellData(i, 'dptArvPreInfoSndYn') == "1")
            && ds_outGrid.getCellData(i, 'gridChkBox') == "1") {
            ds_outGrid.setCellData(i, 'copinoAutoSndYn', "1");
            copinoAutoSndYn = 1;
        }

        //COPINO 팝업전송인 경우 두가지 이상 선택 불가.
        if (p_gubun == "Manual"
            && (ds_outGrid.getCellData(i, 'preInfoSndYn') == "1" || ds_outGrid.getCellData(i, 'dptArvPreInfoSndYn') == "1")
            && ds_outGrid.getCellData(i, 'gridChkBox') == "1") {
            scwin.copinoManualSndYn++;
            copinoRowPosition = i;
        }

        //경기지사 이기성 사원 요청으로
        //20140324 경기지사 박승철 대리 요청 수정
        // ANL 라인,EVER라인  자가 반출인 경우 SEAL 번호 입력하도록 체크
        if ((ds_outGrid.getCellData(i, "lineCd") == "ANL" || ds_outGrid.getCellData(i, "lineCd") == "EVER")
            && (ed_wrkPlCd.getValue() == "4C02" || ed_wrkPlCd.getValue() == "3C01")
            && ds_outGrid.getCellData(i, 'gridChkBox') == "1"
            && ds_outGrid.getCellData(i, "sealNo") == "") {
            if (ds_outGrid.getCellData(i, "lineCd") == "ANL") {
                $c.win.alert("의왕CY에서 ANL라인의 자가 반출인 경우는 SEAL 번호를 입력하셔야 합니다");
            } else {
                $c.win.alert("의왕CY에서 EVER라인의 자가 반출인 경우는 SEAL 번호를 입력하셔야 합니다");
            }
            return false;

        }
        //20161214 APL라인 ANL라인과 동일하게 자가반출시 
        else if (ds_outGrid.getCellData(i, "lineCd") == "APL"
            && ed_wrkPlCd.getValue() == "4C02"
            && ds_outGrid.getCellData(i, 'gridChkBox') == "1"
            && ds_outGrid.getCellData(i, "sealNo") == "") {
            $c.win.alert("의왕CY에서 APL라인의 자가 반출인 경우는 SEAL 번호를 입력하셔야 합니다");
            return false;
        }

        // 미청구된 검색기 ,파출검사료 체크
        if (!$c.gus.cfIsNull(ds_outGrid.getCellData(i, "cxOdrNo"))) {
            if (ds_outGrid.getCellData(i, "cxClntNo") == "999906") {
                $c.win.alert("미청구된 검색기 오더가 존재합니다. 검색기 오더는 :" + ds_outGrid.getCellData(i, "cxOdrNo") + "청구거래처를 고쳐야 오더등록이 가능합니다.!!!");
                return false;
            } else {
                $c.win.alert("미청구된 검색기 오더가 존재합니다. 검색기 오더는 :" + ds_outGrid.getCellData(i, "cxOdrNo"));
            }
        }
        if (!$c.gus.cfIsNull(ds_outGrid.getCellData(i, "ciOdrNo"))) {
            if (ds_outGrid.getCellData(i, "ciClntNo") == "999906") {
                $c.win.alert("미청구된 파출검사 오더가 존재합니다. 파출검사 오더는 :" + ds_outGrid.getCellData(i, "ciOdrNo") + "청구거래처를 고쳐야 오더등록이 가능합니다.!!!");
                return false;
            } else {
                $c.win.alert("미청구된 파출검사 오더가 존재합니다. 파출검사 오더는 :" + ds_outGrid.getCellData(i, "ciOdrNo"));
            }
        }
    }

    if (p_gubun == "Auto" && copinoAutoSndYn == 0) {
        $c.gus.cfAlertMsg("COPINO 전송 대상이 없습니다.");
        return;
    }

    if (p_gubun == "Manual") {
        if (gridChkYn > 1) {
            $c.gus.cfAlertMsg("M/S인 경우 한건만 선택 할 수 있습니다.");
            return;
        }
        if (scwin.copinoManualSndYn == 0) {
            $c.gus.cfAlertMsg("선택하신 사항중 셔틀 COPINO 전송대상이 포함되어 있지 않습니다.");
            return;
        }
    }

    if (gridChkYn == 0) {
        $c.gus.cfAlertMsg("선택된 사항이 없습니다.");
        return;
    }

    //if ( ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'lineCd') == "WJS" && ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'selfClsCd') == "JE" ) {
    if (ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'lineCd') == "WJS"
        && (ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'selfClsCd') == "JE" || ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'selfClsCd') == "LI")) {
        if (ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'odrKndCd') == "C4"
            || ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'odrKndCd') == "C6"
            || (ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'odrKndCd') == "C7" 	// C7오더 vanterm 체크 시작. 2014.08.11 hurrah
                && ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'selfClsCd') == "LI")) {
            if (ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'term') == "" || ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'liVanTerm') == "") {
                $c.win.alert("TERM 항목이 없습니다.");
                return;
            }
            if (ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'term') != ds_outGrid.getCellData(ds_outGrid.getRowPosition(), 'liVanTerm')) {
                $c.win.alert("TERM 항목이 일치하지 않습니다.");
                return;
            }
        }
    }

    //	if (!cfValidate([gr_gridView])) return;

    if (ds_outGrid.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg("선택된 사항이 없습니다.");
    } else {
        let confirm = await $c.win.confirm("Gate Out 처리 하시겠습니까?");
        if (confirm) {
            $c.sbm.execute(sbm_gateOut);
        }
    }
};

scwin.sbm_gateOut_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        // 반출 제어대상 컨테이너
        if (ds_transWrkIndictNo.getCellData(0, 'value') == "InOutImpssbl") {
            $c.win.alert("목적항이 존재하지 않아서 컨테이너 반출이 불가합니다.");
            //return false;
        }
        else {
            //셔틀 반출 이면서 자가반출이 아니고 COPINO 전송대상인 경우 popup창을 띄운다.(셔틀인 조건 제외 2006-08-03)
            if ((ds_outGrid.getCellData(scwin.copinoRowPosition, 'preInfoSndYn') == "1"
                || ds_outGrid.getCellData(scwin.copinoRowPosition, 'dptArvPreInfoSndYn') == "1")
                && scwin.copinoManualSndYn == 1) {
                var copinoWrkIndictNo = ds_outGrid.getCellData(scwin.copinoRowPosition, 'transWrkIndictNo');
                if ($c.util.isEmpty(copinoWrkIndictNo)) {
                    copinoWrkIndictNo = ds_transWrkIndictNo.getCellData(0, 'transWrkIndictNo');
                }

                scwin.f_crryInOutEDI(true, false, false, scwin.copinoRowPosition, false, copinoWrkIndictNo);
            } else {
                $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다 
            }
        }

        scwin.f_retrieve('0');
    }
};

