    if (gridChkYn == 0) {
        $c.gus.cfAlertMsg("선택된 사항이 없습니다.");
        return;
    }

    let confirm = await $c.win.confirm("삭제된 예정정보는 복구할 수 없습니다. 반출입예정정보를 삭제하시겠습니까?");
    if (confirm) {
        $c.sbm.execute(sbm_delete);
    }
};

