//-------------------------------------------------------------------------
// function name : f_RetrieveOdrNo
// function desc : 컨테이너오더정보조회
//-------------------------------------------------------------------------
scwin.f_retrieveOdrNo = async function () {

    let src = "";
    let menuNm = "";
    let menuId = "1111";

    var v_odrNo = ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "odrNo");
    var v_odrKndCd = ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "odrKndCd");

    var strMSG_CM_CRM = "Page로 이동하시겠습니까?";

    paramObj = {};
    paramObj = {
        odrNo: v_odrNo,
        linkPage: "odrList"
    };

    if (v_odrKndCd == "C1" || v_odrKndCd == "CS" || v_odrKndCd == "CT") { // 수입본선오더
        src = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_05b.xml";
        let confirm = await $c.win.confirm("수입본선오더" + strMSG_CM_CRM);
        if (confirm) {
            menuNm = "수입본선오더";
            menuId = "tn_201_02_05b";
            $c.win.openMenu(menuNm, src, menuId, paramObj);
        }
    } else if (v_odrKndCd == "C2") { // 수출일반오더
        src = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_03b.xml";
        let confirm = await $c.win.confirm("수입일반오더" + strMSG_CM_CRM);
        if (confirm) {
            menuNm = "수입일반오더";
            menuId = "tn_201_02_03b";
            $c.win.openMenu(menuNm, src, menuId, paramObj);
        }
    } else if (v_odrKndCd == "C3" || v_odrKndCd == "CW" || v_odrKndCd == "CR" || v_odrKndCd == "CP") { // 수출본선오더
        src = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_06b.xml";
        let confirm = await $c.win.confirm("수출본선오더" + strMSG_CM_CRM);
        if (confirm) {
            menuNm = "수출본선오더";
            menuId = "tn_201_02_06b";
            $c.win.openMenu(menuNm, src, menuId, paramObj);
        }
    } else if (v_odrKndCd == "C4") { // 수출일반오더
        src = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_04b.xml";
        let confirm = await $c.win.confirm("수출일반오더" + strMSG_CM_CRM);
        if (confirm) {
            menuNm = "수출일반오더";
            menuId = "tn_201_02_04b";
            $c.win.openMenu(menuNm, src, menuId, paramObj);
        }
    } else if (v_odrKndCd == "C5" || v_odrKndCd == "C6" || v_odrKndCd == "C7") { // 기타오더
        src = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_07b.xml";
        let confirm = await $c.win.confirm("기타오더" + strMSG_CM_CRM);
        if (confirm) {
            menuNm = "기타오더";
            menuId = "tn_201_02_07b";
            $c.win.openMenu(menuNm, src, menuId, paramObj);
        }
    }
};

