    if (ds_outGrid.getCellData(row, 'cntrSeq') == 0
        && !$c.util.isEmpty(ds_outGrid.getCellData(row, 'cntrNo'))
        && ("B" == ds_outGrid.getCellData(row, 'reqClsCd') || "C" == ds_outGrid.getCellData(row, 'reqClsCd'))) {

        dma_cntrNoSeqInfo.set("cntrNo", ds_outGrid.getCellData(row, 'cntrNo'));
